import{_ as e,o as a,c as i,a2 as s}from"./chunks/framework.Bk_3gXAz.js";const u=JSON.parse('{"title":"medical-research","description":"Evidence-based medical writing protocol for OB/GYN research articles. Ensures citation standards, Level of Evidence grading, anti-hallucination rules, and clinical accuracy markers. Use when generating or reviewing medical content.","frontmatter":{"title":"medical-research","name":"medical-research","description":"Evidence-based medical writing protocol for OB/GYN research articles. Ensures citation standards, Level of Evidence grading, anti-hallucination rules, and clinical accuracy markers. Use when generating or reviewing medical content.","allowed-tools":"Read, Write, Edit, Bash","version":1,"priority":"HIGH"},"headers":[],"relativePath":"skills/medical-research.md","filePath":"skills/medical-research.md"}'),n={name:"skills/medical-research.md"};function r(o,t,d,l,c,h){return a(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="medical-research-—-evidence-based-writing-protocol" tabindex="-1">Medical Research — Evidence-Based Writing Protocol <a class="header-anchor" href="#medical-research-—-evidence-based-writing-protocol" aria-label="Permalink to &quot;Medical Research — Evidence-Based Writing Protocol&quot;">​</a></h1><blockquote><p><strong>Mandatory</strong> when writing medical articles for the OB/GYN RND system.</p></blockquote><hr><h2 id="_1-evidence-grading-—-oxford-cebm" tabindex="-1">1. Evidence Grading — Oxford CEBM <a class="header-anchor" href="#_1-evidence-grading-—-oxford-cebm" aria-label="Permalink to &quot;1. Evidence Grading — Oxford CEBM&quot;">​</a></h2><p>Every recommendation/protocol in articles <strong>MUST</strong> include Level of Evidence:</p><table tabindex="0"><thead><tr><th>Level</th><th>Evidence Type</th><th>In-Article Notation</th></tr></thead><tbody><tr><td><strong>I</strong></td><td>Systematic Review / Meta-analysis / Large RCT</td><td><code>[LoE: I]</code></td></tr><tr><td><strong>II</strong></td><td>Small RCT / High-quality Cohort study</td><td><code>[LoE: II]</code></td></tr><tr><td><strong>III</strong></td><td>Case-control study / Retrospective Cohort</td><td><code>[LoE: III]</code></td></tr><tr><td><strong>IV</strong></td><td>Case series / Cross-sectional</td><td><code>[LoE: IV]</code></td></tr><tr><td><strong>V</strong></td><td>Expert opinion / Consensus</td><td><code>[LoE: V]</code></td></tr></tbody></table><p><strong>Rules:</strong></p><ul><li>Each pathology article (Tier 2) must have <strong>at least 3 recommendations with LoE</strong></li><li>Each technique article (Tier 3) must have <strong>at least 2 recommendations with LoE</strong></li><li>Each foundation article (Tier 1) must have <strong>at least 1 LoE</strong></li><li>Include LoE <strong>inline</strong> right after the recommendation, e.g.: <code>Aspirin 150mg from week 12 for high-risk group [LoE: I — ASPRE trial 2017]</code></li></ul><hr><h2 id="_2-citation-standard-—-mandatory-references" tabindex="-1">2. Citation Standard — Mandatory References <a class="header-anchor" href="#_2-citation-standard-—-mandatory-references" aria-label="Permalink to &quot;2. Citation Standard — Mandatory References&quot;">​</a></h2><h3 id="accepted-sources-in-priority-order" tabindex="-1">Accepted Sources (in priority order) <a class="header-anchor" href="#accepted-sources-in-priority-order" aria-label="Permalink to &quot;Accepted Sources (in priority order)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Priority</th><th>Source</th><th>Citation Example</th></tr></thead><tbody><tr><td><strong>P0</strong></td><td>National MoH Guidelines</td><td><code>[MoH 2023 — Diagnosis and Treatment Guidelines]</code></td></tr><tr><td><strong>P1</strong></td><td>ACOG Practice Bulletin</td><td><code>[ACOG PB #234, 2024]</code></td></tr><tr><td><strong>P1</strong></td><td>ASRM Committee Opinion</td><td><code>[ASRM CO 2023]</code></td></tr><tr><td><strong>P1</strong></td><td>ESHRE Guideline</td><td><code>[ESHRE Guideline 2024]</code></td></tr><tr><td><strong>P2</strong></td><td>WHO Recommendation</td><td><code>[WHO 2023]</code></td></tr><tr><td><strong>P2</strong></td><td>Cochrane Systematic Review</td><td><code>[Cochrane 2023]</code></td></tr><tr><td><strong>P3</strong></td><td>NICE / RCOG</td><td><code>[NICE NG000, 2024]</code></td></tr><tr><td><strong>P3</strong></td><td>UpToDate / Standard Textbook</td><td><code>[Williams Obstetrics 26th Ed]</code></td></tr></tbody></table><h3 id="citation-rules" tabindex="-1">Citation Rules <a class="header-anchor" href="#citation-rules" aria-label="Permalink to &quot;Citation Rules&quot;">​</a></h3><ul><li>Each article <strong>MUST</strong> have a <code>## REFERENCES</code> section at the end</li><li>Each pathology article (T2) must cite <strong>≥ 3 different guidelines</strong></li><li>Each technique article (T3) must cite <strong>≥ 2 guidelines</strong></li><li>Each foundation article (T1) must cite <strong>≥ 2 guidelines</strong></li><li>Cite <strong>inline</strong> within text, e.g.: <code>According to ACOG PB #234 (2024), IVF success rate in women &gt; 40 is 15-20%</code></li><li><strong>DO NOT</strong> accept vague citations: <s>&quot;According to research&quot;</s>, <s>&quot;Experts suggest&quot;</s></li></ul><hr><h2 id="_3-anti-hallucination-rules-—-no-fabrication" tabindex="-1">3. Anti-Hallucination Rules — No Fabrication <a class="header-anchor" href="#_3-anti-hallucination-rules-—-no-fabrication" aria-label="Permalink to &quot;3. Anti-Hallucination Rules — No Fabrication&quot;">​</a></h2><blockquote><p>🔴 <strong>CRITICAL:</strong> The most important rules for medical content.</p></blockquote><table tabindex="0"><thead><tr><th>Rule</th><th>Description</th><th>Violation Example</th></tr></thead><tbody><tr><td><strong>No fabricated statistics</strong></td><td>Do not invent percentages or statistical figures</td><td>❌ &quot;Success rate 87.3%&quot; (no source)</td></tr><tr><td><strong>No fabricated drugs</strong></td><td>Only list real medications with correct dosages</td><td>❌ Inventing non-existent brand names</td></tr><tr><td><strong>No fabricated guidelines</strong></td><td>Only cite real, existing guidelines</td><td>❌ &quot;ACOG PB #999&quot; (doesn&#39;t exist)</td></tr><tr><td><strong>No fabricated studies</strong></td><td>Do not create fake author names/years</td><td>❌ &quot;According to Smith et al. (2024)...&quot; (fabricated)</td></tr><tr><td><strong>When uncertain → state clearly</strong></td><td>Write &quot;Data varies...&quot; or use ranges</td><td>✅ &quot;Rate ~10-20% (varies by study)&quot;</td></tr></tbody></table><h3 id="safe-phrases-when-exact-data-is-missing" tabindex="-1">Safe Phrases When Exact Data Is Missing <a class="header-anchor" href="#safe-phrases-when-exact-data-is-missing" aria-label="Permalink to &quot;Safe Phrases When Exact Data Is Missing&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ &quot;Rate ranges from X-Y% depending on the study&quot;</span></span>
<span class="line"><span>✅ &quot;Based on available literature, estimated at approximately...&quot;</span></span>
<span class="line"><span>✅ &quot;Local data is limited; international reports indicate...&quot;</span></span>
<span class="line"><span>✅ &quot;Further research needed to confirm&quot;</span></span>
<span class="line"><span>❌ &quot;Exactly XX.X%&quot; (when no specific source exists)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="_4-clinical-safety-markers-—-medical-markup" tabindex="-1">4. Clinical Safety Markers — Medical Markup <a class="header-anchor" href="#_4-clinical-safety-markers-—-medical-markup" aria-label="Permalink to &quot;4. Clinical Safety Markers — Medical Markup&quot;">​</a></h2><p>Each pathology article (T2) <strong>MUST</strong> include all 4 markers:</p><table tabindex="0"><thead><tr><th>Marker</th><th>Purpose</th><th>Format</th></tr></thead><tbody><tr><td><code>&gt; 💊 CLINICAL NOTE</code></td><td>Most important practice consideration</td><td>Blockquote</td></tr><tr><td><code>&gt; ⚠️ RED FLAG</code></td><td>When urgent intervention / referral is needed</td><td>Blockquote</td></tr><tr><td><code>&gt; 📚 REFERENCE</code></td><td>Primary guideline for this topic</td><td>Blockquote</td></tr><tr><td><code>&gt; ⚕️ DISCLAIMER</code></td><td>Specialist consultation required</td><td>Blockquote at end</td></tr></tbody></table><h3 id="mandatory-disclaimer-end-of-each-article" tabindex="-1">Mandatory Disclaimer (end of each article) <a class="header-anchor" href="#mandatory-disclaimer-end-of-each-article" aria-label="Permalink to &quot;Mandatory Disclaimer (end of each article)&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">&gt; ⚕️ </span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**DISCLAIMER:**</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;"> This article is for medical reference purposes only.</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">&gt; All diagnostic and treatment decisions </span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**require specialist physician guidance**</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">.</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">&gt; Do not self-apply protocols without specific clinical evaluation.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h2 id="_5-cross-reference-protocol" tabindex="-1">5. Cross-Reference Protocol <a class="header-anchor" href="#_5-cross-reference-protocol" aria-label="Permalink to &quot;5. Cross-Reference Protocol&quot;">​</a></h2><h3 id="inter-article-links" tabindex="-1">Inter-Article Links <a class="header-anchor" href="#inter-article-links" aria-label="Permalink to &quot;Inter-Article Links&quot;">​</a></h3><ul><li>When mentioning a pathology/technique with its own article → <strong>MUST include article code</strong></li><li>Format: <code>→ See details: [VSN-04] Endometriosis</code></li><li>Section <code>## CROSS-LINKS</code> must list all related articles</li></ul><h3 id="icd-10" tabindex="-1">ICD-10 <a class="header-anchor" href="#icd-10" aria-label="Permalink to &quot;ICD-10&quot;">​</a></h3><ul><li>Pathology articles (T2) with ICD-10 codes → <strong>MUST include in header</strong></li><li>Format: <code>&gt; **ICD-10:** N97.0 | **Group:** VSN</code></li></ul><hr><h2 id="_6-medical-writing-audit-—-8-dimension-evaluation" tabindex="-1">6. Medical Writing Audit — 8-Dimension Evaluation <a class="header-anchor" href="#_6-medical-writing-audit-—-8-dimension-evaluation" aria-label="Permalink to &quot;6. Medical Writing Audit — 8-Dimension Evaluation&quot;">​</a></h2><p>When reviewing medical articles, score across 8 dimensions (1-10):</p><table tabindex="0"><thead><tr><th>Dimension</th><th>Question</th><th>Passing Standard</th></tr></thead><tbody><tr><td><strong>1. Evidence Quality</strong></td><td>Are LoE markers on key recommendations?</td><td>≥ 3 LoE markers</td></tr><tr><td><strong>2. Citation Depth</strong></td><td>Are specific guidelines cited?</td><td>≥ 3 different sources</td></tr><tr><td><strong>3. Clinical Accuracy</strong></td><td>Are drug doses, metrics correct?</td><td>No medical errors</td></tr><tr><td><strong>4. Structure</strong></td><td>Correct template, all sections present?</td><td>100% sections with content</td></tr><tr><td><strong>5. ICD-10 Compliance</strong></td><td>Correct ICD-10 code present?</td><td>Header has ICD-10</td></tr><tr><td><strong>6. Safety Markers</strong></td><td>Red Flag, Disclaimer present?</td><td>4/4 markers</td></tr><tr><td><strong>7. Cross-References</strong></td><td>Links to related articles?</td><td>≥ 2 cross-links</td></tr><tr><td><strong>8. Word Count</strong></td><td>Meets minimum length?</td><td>T1≥1500, T2≥2000, T3≥1500</td></tr></tbody></table><p><strong>Scoring:</strong></p><ul><li><strong>72-80:</strong> Excellent — publish ready</li><li><strong>56-71:</strong> Good — minor revisions needed</li><li><strong>40-55:</strong> Average — needs more evidence</li><li><strong>&lt; 40:</strong> Fail — rewrite</li></ul><hr><h2 id="_7-template-enhancement-rules" tabindex="-1">7. Template Enhancement Rules <a class="header-anchor" href="#_7-template-enhancement-rules" aria-label="Permalink to &quot;7. Template Enhancement Rules&quot;">​</a></h2><p>When creating new articles, inject these additional requirements into the prompt:</p><h3 id="for-pathology-articles-t2" tabindex="-1">For Pathology Articles (T2) <a class="header-anchor" href="#for-pathology-articles-t2" aria-label="Permalink to &quot;For Pathology Articles (T2)&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>EVIDENCE-BASED REQUIREMENTS:</span></span>
<span class="line"><span>1. Each treatment recommendation includes [LoE: I-V] + source</span></span>
<span class="line"><span>2. &quot;DIAGNOSIS&quot; section must have a test table with &quot;Source Guideline&quot; column</span></span>
<span class="line"><span>3. &quot;TREATMENT&quot; section must cite specific protocols (ACOG/MoH/ASRM)</span></span>
<span class="line"><span>4. End of article has &quot;## REFERENCES&quot; listing ≥ 3 guidelines</span></span>
<span class="line"><span>5. End of article has medical DISCLAIMER</span></span>
<span class="line"><span>6. DO NOT fabricate statistics — use estimated ranges when exact data is unavailable</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="for-technique-articles-t3" tabindex="-1">For Technique Articles (T3) <a class="header-anchor" href="#for-technique-articles-t3" aria-label="Permalink to &quot;For Technique Articles (T3)&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>EVIDENCE-BASED REQUIREMENTS:</span></span>
<span class="line"><span>1. Each procedure step cites source protocol (ASRM/ESHRE/MoH)</span></span>
<span class="line"><span>2. Drug tables must have a &quot;Guideline&quot; column</span></span>
<span class="line"><span>3. Success rates must cite source + confidence interval</span></span>
<span class="line"><span>4. End of article has &quot;## REFERENCES&quot; ≥ 2 guidelines</span></span>
<span class="line"><span>5. End of article has medical DISCLAIMER</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><hr><h2 id="verification-script" tabindex="-1">Verification Script <a class="header-anchor" href="#verification-script" aria-label="Permalink to &quot;Verification Script&quot;">​</a></h2><p>Run after article generation to check quality:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.gemini/antigravity/skills/medical-research/scripts/evidence_checker.py</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">output_di</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">r</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Script checks: References, LoE markers, ICD-10, Disclaimer, word count, cross-links.</p><hr><h2 id="quick-diagnostic" tabindex="-1">Quick Diagnostic <a class="header-anchor" href="#quick-diagnostic" aria-label="Permalink to &quot;Quick Diagnostic&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Question</th><th>If NO</th><th>Action</th></tr></thead><tbody><tr><td>Has REFERENCES section?</td><td>Article lacks sources</td><td>Add ≥ 3 guidelines</td></tr><tr><td>Has LoE for recommendations?</td><td>Unclear reliability</td><td>Assign LoE I-V</td></tr><tr><td>Has ICD-10 in header?</td><td>Missing coding</td><td>Add ICD-10</td></tr><tr><td>Has RED FLAG?</td><td>Missing clinical warning</td><td>Add ⚠️ marker</td></tr><tr><td>Has DISCLAIMER?</td><td>Legal risk</td><td>Add disclaimer at end</td></tr><tr><td>Do statistics have sources?</td><td>Suspected hallucination</td><td>Convert to estimated ranges</td></tr></tbody></table>`,53)])])}const g=e(n,[["render",r]]);export{u as __pageData,g as default};
